// Nodo: Preparar Requerimientos API Google Docs
// Proyecto: Automatización de Fraudes Bancarios 2026

// Asegúrate de que estos nombres coincidan EXACTAMENTE con los de tus nodos
const data = $('Code in JavaScript').first().json; 
const docId = $('Copiar Plantilla2').first().json.id;

// CORRECCIÓN AQUÍ: Llamamos a "GET Documento1"
const doc = $('GET Documento1').first().json; 
const transacciones = JSON.parse(data.tabla_transaccion || "[]").filter(t => t.Fecha);

// Definimos la cantidad de filas (Datos + Encabezado)
const numRows = transacciones.length + 1;

// Buscar el índice exacto de {{tabla_texto}} en la estructura del documento
let targetIndex = 1; // Índice por defecto (inicio) como fallback
if (doc && doc.body && doc.body.content) {
  for (const element of doc.body.content) {
    if (element.paragraph && element.paragraph.elements) {
      for (const el of element.paragraph.elements) {
        if (el.textRun && el.textRun.content.includes("{{tabla_texto}}")) {
          targetIndex = el.startIndex;
          break;
        }
      }
    }
    if (targetIndex !== 1) break; // Detener la búsqueda si ya lo encontramos
  }
}

return {
  documentId: docId,
  requests: [
    {
      // Paso 1: Insertar la estructura de la tabla nativa en el índice exacto
      "insertTable": {
        "rows": numRows,
        "columns": 5,
        "location": { "index": targetIndex } 
      }
    },
    {
      // Paso 2: Eliminar el marcador {{tabla_texto}} de forma global
      "replaceAllText": {
        "containsText": { "text": "{{tabla_texto}}", "matchCase": true },
        "replaceText": "" 
      }
    }
  ]
};

// Nodo: Preparar Datos Demanda (Texto Simple)
// Objetivo: Formatear variables para placeholders de Google Docs
// Proyecto: Automatización de Fraudes Bancarios 2026

return $input.all().map(item => {
  const data = item.json;

  // 1. Formateo de Monto Reclamado (Moneda CLP)
  const montoFormateado = (data.monto_reclamado || 0).toLocaleString('es-CL');

  // 2. Limpieza de Puntos de Ataque (JSON Array -> Texto para Word)
  // Convierte el array JSON en párrafos separados por doble salto de línea
  let puntosAtaqueLimpio = "";
  try {
    const puntos = JSON.parse(data.puntos_ataque || "[]");
    puntosAtaqueLimpio = puntos.join('\n\n');
  } catch (e) {
    puntosAtaqueLimpio = data.puntos_ataque || "";
  }

  // 3. Formateo de Fecha de Aviso (ISO -> YYYY-MM-DD)
  const fechaLimpia = data.fecha_aviso ? data.fecha_aviso.split('T')[0] : "";

  return {
    json: {
      ...data, // Mantenemos el ID_Maestro y originales para persistencia en Supabase
      monto_formateado: `$${montoFormateado}`,
      puntos_ataque_limpio: puntosAtaqueLimpio,
      fecha_aviso_doc: fechaLimpia,
      // Aseguramos compatibilidad con los tags de tu plantilla .docx
      placeholder_tribunal: data.tribunal || "Juzgado correspondiente",
      placeholder_rut: data.rut_demandado || "",
      placeholder_domicilio: data.domicilio_demandado || ""
    }
  };
});

const data = $('Code in JavaScript').first().json;
const docId = $('Copiar Plantilla2').first().json.id;
const transacciones = JSON.parse(data.tabla_transaccion || "[]").filter(t => t.Fecha);

const filas = [
  ['Fecha', 'Tarjeta', 'Monto', 'Comercio', 'Canal']
];

transacciones.forEach(t => {
  filas.push([
    (t.Fecha || "").split(' ')[0],
    t.Tarjeta || "",
    "$" + (t["Monto Transaccion"] || 0).toLocaleString('es-CL'),
    (t["Nombre del Comercio"] || "").substring(0, 15),
    (t.Canal || "").substring(0, 10)
  ]);
});

const numCols = 5;

const docContent = $('GET Documento').first().json;
const bodyContent = docContent.body.content;

const tablasEnDoc = bodyContent.filter(e => e.table);
if (tablasEnDoc.length === 0) {
  throw new Error("No se encontro ninguna tabla en el documento.");
}
const tabla = tablasEnDoc[tablasEnDoc.length - 1];

let requests = [];

for (let r = filas.length - 1; r >= 0; r--) {
  for (let c = numCols - 1; c >= 0; c--) {
    const fila = tabla.table.tableRows[r];
    if (!fila) {
      throw new Error("Fila " + r + " no existe. Filas disponibles: " + tabla.table.tableRows.length);
    }
    const celda = fila.tableCells[c];
    if (!celda) {
      throw new Error("Celda [" + r + "][" + c + "] no existe.");
    }

    const cellIndex = celda.content[0].startIndex;

    requests.push({
      insertText: {
        location: { index: cellIndex },
        text: filas[r][c] || " "
      }
    });
  }
}

return {
  documentId: docId,
  requests: requests
};

/**
 * Nodo: agrupa
 * Descripción: Consolida la información de las 3 fuentes documentales (Certificado, 
 * Declaración y Denuncia) en un único objeto JSON vinculado al ID Maestro.
 */

// 1. Rescatamos todos los items que llegan desde el nodo Merge
const items = $input.all();

// 2. Definimos variables para la consolidación
let idMaestro = "";
let textoConsolidado = "";
let documentosProcesados = [];

// 3. Iteramos sobre los documentos recibidos
items.forEach((item, index) => {
  // Extraemos el ID Maestro del primer item (es universal para el caso)
  if (index === 0) {
    idMaestro = item.json.id_maestro_rel || "Sin_ID_Maestro";
  }

  const clasificacion = item.json.clasificacion || "Documento No Identificado";
  const contenido = item.json.transcripcion || item.json.transcripcion_resumen_ia || "Sin contenido detectable";

  // Estructuramos el bloque de texto para el Agente de IA
  textoConsolidado += `==========================================\n`;
  textoConsolidado += `FUENTE: ${clasificacion.toUpperCase()}\n`;
  textoConsolidado += `==========================================\n`;
  textoConsolidado += `${contenido}\n\n`;

  // Guardamos referencia de qué documentos se incluyeron
  documentosProcesados.push(clasificacion);
});

// 4. Retornamos un ÚNICO item con toda la data unificada
return [{
  json: {
    id_maestro_rel: idMaestro,
    transcripcion_resumen_ia: textoConsolidado.trim(),
    meta: {
      total_documentos: items.length,
      lista_documentos: documentosProcesados,
      fecha_agrupacion: new Date().toISOString()
    }
  }
}];

/**
 * Nodo: ordena+id
 * Propósito: Parsear la respuesta de la IA (Nuevo Esquema) y vincularla al ID Maestro.
 * Proyecto: Automatización de Fraudes Bancarios 2026
 */

