    puntosAtaqueLimpio = data.puntos_ataque || "";
  }

  // 3. Formateo de Fecha de Aviso (ISO -> YYYY-MM-DD)
  const fechaLimpia = data.fecha_aviso ? data.fecha_aviso.split('T')[0] : "";

  return {
    json: {
      ...data, // Mantenemos el ID_Maestro y originales para persistencia en Supabase
      monto_formateado: `$${montoFormateado}`,
      puntos_ataque_limpio: puntosAtaqueLimpio,
      fecha_aviso_doc: fechaLimpia,
      // Aseguramos compatibilidad con los tags de tu plantilla .docx
      placeholder_tribunal: data.tribunal || "Juzgado correspondiente",
      placeholder_rut: data.rut_demandado || "",
      placeholder_domicilio: data.domicilio_demandado || ""
    }
  };
});

const data = $('Code in JavaScript7').first().json;
const docId = $('Copiar Plantilla7').first().json.id;
const transacciones = JSON.parse(data.tabla_transaccion || "[]").filter(t => t.Fecha);

const filas = [
  ['Fecha', 'Tarjeta', 'Monto', 'Comercio', 'Canal']
];

transacciones.forEach(t => {
  filas.push([
    (t.Fecha || "").split(' ')[0],
    t.Tarjeta || "",
    "$" + (t["Monto Transaccion"] || 0).toLocaleString('es-CL'),
    (t["Nombre del Comercio"] || "").substring(0, 15),
    (t.Canal || "").substring(0, 10)
  ]);
});

const numCols = 5;

const docContent = $('GET Documento14').first().json;
const bodyContent = docContent.body.content;

const tablasEnDoc = bodyContent.filter(e => e.table);
if (tablasEnDoc.length === 0) {
  throw new Error("No se encontro ninguna tabla en el documento.");
}
const tabla = tablasEnDoc[tablasEnDoc.length - 1];

let requests = [];

for (let r = filas.length - 1; r >= 0; r--) {
  for (let c = numCols - 1; c >= 0; c--) {
    const fila = tabla.table.tableRows[r];
    if (!fila) {
      throw new Error("Fila " + r + " no existe. Filas disponibles: " + tabla.table.tableRows.length);
    }
    const celda = fila.tableCells[c];
    if (!celda) {
      throw new Error("Celda [" + r + "][" + c + "] no existe.");
    }

    const cellIndex = celda.content[0].startIndex;

    requests.push({
      insertText: {
        location: { index: cellIndex },
        text: filas[r][c] || " "
      }
    });
  }
}

return {
  documentId: docId,
  requests: requests
};

// Nodo: defensa
// Descripción: Generador dinámico de conclusiones jurídicas (Ley 21.234) - MULTICANAL
// Proyecto: Automatización de Fraudes Bancarios 2026

for (const item of $input.all()) {
  // 1. Capturamos el canal de operación (soportando texto simple, múltiple o array)
  let canalRaw = item.json.canal_operacion || "";
  let canal = (Array.isArray(canalRaw) ? canalRaw.join(" ") : String(canalRaw)).toLowerCase();

  let argumentos = [];

  // 2. Lógica de redacción acumulativa (Detecta todos los canales presentes)
  if (canal.includes("apple") || canal.includes("wallet") || canal.includes("google") || canal.includes("nfc")) {
    argumentos.push(
      "Respecto a las operaciones vía billetera digital (Apple Pay/Google Wallet), la sola invocación de una supuesta 'autenticación reforzada' no exime al banco de su deber legal. El sistema falló en detectar el enrolamiento anómalo y el patrón de consumo atípico, lo que evidencia una negligencia inexcusable en el monitoreo (SOC) por parte de la institución."
    );
  }

  if (canal.includes("chip") || canal.includes("atm") || canal.includes("presencial") || canal.includes("cajero")) {
    argumentos.push(
      "En cuanto a las transacciones presenciales (Chip/Contactless/ATM), la validación tecnológica no acredita la presencia física de mi representado, dada la proliferación de técnicas de clonación ('skimming'). Además, el banco no acompaña registros audiovisuales (CCTV) que posicionen al demandado en el lugar de los hechos, incumpliendo su estándar probatorio."
    );
  }

  if (canal.includes("web") || canal.includes("transferencia") || canal.includes("internet") || canal.includes("online")) {
    argumentos.push(
      "Sobre las operaciones vía web o transferencias electrónicas, los sistemas de ciberseguridad y prevención de fraudes del banco resultaron vulnerados o ineficaces frente a ataques externos (ej. Phishing/Malware), permitiendo el agotamiento de fondos sin levantar alertas ni bloqueos preventivos eficaces."
    );
  }

  // Si por alguna razón no detecta palabras clave reconocidas, inyecta un argumento general táctico
  if (argumentos.length === 0) {
    argumentos.push(
      "Sobre las operaciones cuestionadas, las medidas de seguridad de la institución resultaron ineficaces para detectar este comportamiento transaccional inusual, vulnerando el patrimonio del cliente sin mediar alertas de fraude."
    );
  }

  // 3. Ensamblaje de la estructura argumentativa final
  let textoConclucion = "a. En primer lugar, la Ley 21.234 establece un régimen de responsabilidad estricta que invierte la carga de la prueba, obligando a la institución financiera a demostrar, bajo un estándar riguroso, el dolo o culpa grave del usuario en la vulneración de sus canales de atención.\n\n";

  // Añadimos viñetas dinámicas (b, c, d...) según la cantidad de canales detectados
  let letras = ['b', 'c', 'd', 'e', 'f'];
  argumentos.forEach((arg, index) => {
    textoConclucion += `${letras[index]}. En relación al canal vulnerado, ${arg}\n\n`;
  });

  // Párrafo de cierre fijo
  let ultimaLetra = letras[argumentos.length];
  textoConclucion += `${ultimaLetra}. Consecuentemente, no existiendo prueba irrefutable de participación directa, dolo o culpa grave por parte de mi representado, y habiendo este cumplido con el oportuno aviso y bloqueo de sus productos, corresponde legalmente la restitución íntegra de los fondos sustraídos.`;

  // 4. Inyectamos la variable final para Google Docs
  item.json.conclucion = textoConclucion;

  // Persistencia estricta de la llave maestra para Supabase (Expedientes_Core / Expediente)
  item.json.id_maestro_rel = item.json.id_maestro || item.json.id_maestro_rel;
}

return $input.all();
